import {EmotionSystem, EmotionEvents} from "./EmotionSystem";
import {Emotion} from "./emotion/Emotion";
import {InitOptions, EmotionPoint, EmotionImpact} from "./common/Types";
import {ImpactValues} from "./emotion/EmotionDefinitions";
import { AnimQuery } from "jibo-anim-db";

export * from './common/Types';

export { Emotion };

/*
 * Private variables
 */

/**
 * Various events emitted by the emotion system.
 * @name jibo.emotion#events
 * @type {jibo.emotion.EmotionEvents}
 * @intdocs
 */
export let events: EmotionEvents;

/**
 * The instance of the runtime. We expose it on the API just for
 * testing and special circumstances. Not meant to be accessed for standard use.
 * @type {jibo.emotion.EmotionSystem}
 * @internal
 * @private
 */
export let _runtime: EmotionSystem;

/*
 * Public API methods
 */

/**
 * Initializes the emotion system.
 * @method jibo.emotion#init
 * @param {jibo.emotion.InitOptions} initOptions options to init with jibo.
 * @returns {Promise<void>} A promise that is resolved when the emotion system has been initialized
 * @intdocs
 */
export function init(initOptions:InitOptions): Promise<void> {
    _runtime = new EmotionSystem();
    events = _runtime.events;
    return _runtime.init(initOptions);
}

/**
 * Get the nearest labeled emotion to Jibo's current emotional state.
 * (Mapped to a set of pre-defined states).
 * @method jibo.emotion#getNearestEmotion
 * @returns {jibo.emotion.Emotion}
 * @intdocs
 */
export function getNearestEmotion(): Emotion {
    return _runtime.getNearestEmotion();
}

/**
 * Get Jibo's exact current emotional state.
 * @method jibo.emotion#getCurrentEmotionalValues
 * @returns {jibo.emotion.EmotionPoint}
 * @intdocs
 */
export function getCurrentEmotionalValues(): EmotionPoint {
    return _runtime.getCurrentEmotionalValues();
}

/**
 * Supports skills impacting jibo's emotional state using a set of offered impacts
 * @param {jibo.emotion.EmotionImpact} impact The impact to effect Jibo's emotional state
 * @method jibo.emotion#triggerImpact
 * @intdocs
 */
export function triggerImpact(impact: EmotionImpact): void {
    let valenceImpact = ImpactValues.get(impact.valence) || 0;
    let confidenceImpact = ImpactValues.get(impact.confidence) || 0;
    const emoImpact = new EmotionPoint(valenceImpact, confidenceImpact);
    _runtime.triggerImpact(emoImpact);
}

/**
 * Tell the emotion system to react to a set of head pads being touch.
 * Get the animation that the emotion system thinks should be played.
 * See the [head touch sensor diagram](https://app-toolkit.jibo.com/images/JiboHeadSensors.png).
 * @method jibo.emotion#reactToHeadTouch
 * @param {boolean[]} pads `true` for head pads that were touched.
 * @returns {jibo.animdb#AnimQuery | null} query to be played or none if none applies
 * @intdocs
 */
export function reactToHeadTouch(pads: boolean[]): AnimQuery | null {
    return _runtime.reactToHeadTouch(pads);
}