import {Event, EventContainer} from 'jibo-typed-events';
import {EmotionTrace} from '../../emotion/EmotionTrace';
import {EmotionSystem} from "../../EmotionSystem";

export {};

/**
 * @internal
 */
export class AppraisalRuleEvents extends EventContainer {

    impactTriggered = new Event<EmotionTrace>('Impact has been triggered.');
}


/**
 * @internal
 */
export abstract class AppraisalRule {

    public events = new AppraisalRuleEvents();

    constructor(public name: string, protected parent: EmotionSystem) {
        return;
    }

    /**
     * @param {*} data Any data to initialize rule.
     */
    abstract init(data: any): void;

    /**
     */
    abstract dispose(): void;


    /**
     * @param {*} data Any input data to appraise.
     */
    abstract appraiseData(data: any): void;
}
