import {Utils} from '../common/Utils';
import {EmotionName, EmotionPoint} from "../common/Types";

/**
 * @class Emotion
 * @memberOf jibo.emotion
 * @description The most basic format of Jibo's emotional states.
 * @intdocs
 */
export class Emotion {

    /**
     * The name of this emotion
     * @type {jibo.emotion.EmotionName}
     * @name jibo.emotion.Emotion#name
     * @intdocs
     */
    public name: EmotionName;
    /**
     * The emotional parameter values of this state.
     * @type {jibo.emotion.EmotionPoint}
     * @name jibo.emotion.Emotion#values
     * @intdocs
     * @protected
     */
    protected values: EmotionPoint;

    constructor(name: EmotionName, valence: number=0, confidence: number=0) {
        this.name = name;
        this.values = new EmotionPoint(valence, confidence);
    }

    /**
     * The emotional valance of this emotional state [-1,1]
     * @type {jibo.emotion.EmotionPoint}
     * @name jibo.emotion.Emotion#emotionValues
     * @intdocs
     */
    public get emotionValues():EmotionPoint {
        return this.values;
    }

    public set emotionValues(values: EmotionPoint) {
        this.values.valence = Utils.limitToRange(values.valence, -1, 1);
        this.values.confidence = Utils.limitToRange(values.confidence, -1, 1);
    }
}
