import { EmotionName as CT_EmotionName } from 'jibo-common-types';

export import EmotionName = CT_EmotionName;

/**
 * @class jibo.emotion.EmotionPoint
 * @prop {number} [valence=0]
 * @prop {number} [confidence=0]
 * @intdocs
 */
export class EmotionPoint {
    constructor(public valence: number = 0, public confidence: number = 0) {
    }
}

/**
 * An enum of atomic Emotional Impacts that skills can use via the skill sensor
 * to influence the valence and confidence of jibo's emotions.
 * ```
 * import { EmotionName, ImpactSize, EmotionImpact } from 'jibo-emotion-system';
 * const impact: ImpactSize = {
 *     valence: ImpactSize.HIGH_POS,
 *     confidence: ImpactSize.MEDIUM_POS
 * }
 * jibo.emotion.triggerImpact(impact);
 * const emotion = jibo.emotion.getNearestEmotion();
 * // emotion.name should equal EmotionName.JOYFUL
 * ```
 * @memberof jibo.emotion
 * @typedef ImpactSize
 * @property {string} NONE Impact an axis of Jibo's emotions with no effect.
 * @property {string} LOW_POS Impact an axis of Jibo's emotions with low positive effect.
 * @property {string} MEDIUM_POS Impact an axis of Jibo's emotions with medium positive effect.
 * @property {string} HIGH_POS Impact an axis of Jibo's emotions with high positive effect.
 * @property {string} LOW_NEG Impact an axis of Jibo's emotions with low negative effect.
 * @property {string} MEDIUM_NEG Impact an axis of Jibo's emotions with medium negative effect.
 * @property {string} HIGH_NEG Impact an axis of Jibo's emotions with high negative effect.
 * @intdocs
 */
export enum ImpactSize {
    NONE = 'NONE',
    LOW_POS = 'LOW_POS',
    MEDIUM_POS = 'MEDIUM_POS',
    HIGH_POS = 'HIGH_POS',
    LOW_NEG = 'LOW_NEG',
    MEDIUM_NEG = 'MEDIUM_NEG',
    HIGH_NEG = 'HIGH_NEG',
}

/**
 * Interface to impact Jibo's emotional state via `jibo.emotion.triggerImpact()`
 * ```
 * import { EmotionName, ImpactSize, EmotionImpact } from 'jibo-emotion-system';
 * const impact: EmotionImpact = {
 *     valence: ImpactSize.HIGH_POS,
 *     confidence: ImpactSize.MEDIUM_POS
 * }
 * jibo.emotion.triggerImpact(impact);
 * const emotion = jibo.emotion.getNearestEmotion();
 * // emotion.name should equal EmotionName.JOYFUL
 * ```
 * @memberof jibo.emotion
 * @intdocs
 * @interface EmotionImpact
 * @property {jibo.emotion.ImpactSize} [valence=NONE] The impact size to impact Jibo's emotional valence.
 * @property {jibo.emotion.ImpactSize} [confidence=NONE] The impact size to impact Jibo's emotional confidence.
 */
export interface EmotionImpact {
    valence?:ImpactSize;
    confidence?: ImpactSize;
}

