import * as appraisal from './appraisal';
import * as emotion from './emotion';
import * as sensing from './sensing';
import * as expression from './expression';
import * as api from './api';
import * as emotionSystem from './EmotionSystem';
import * as common from './common';

/**
 * @intdocs
 * @description Jibo's emotion system is a package that internally manages Jibo's internal
 * emotional state by monitoring sensory inputs, and can be queried for his emotional
 * state, history, and trajectory. Currently, the api does not allow external manipulation
 * of his emotional states.
 *
 * Jibo's Emotion System takes a list of emotions and plots them into a 2-dimensional space.
 * We use a nearest neighbor query to find the nearest emotional label
 * for our current emotional position, based on how "Confident (Confident/Insecure)"
 * and "Joyful (Positive/Negative Valence)" we currently are.
 *
 * ```
 *                           *Confidence*
 * <Hopeful>                      | <Confident>              <Joyful>
 * (-1, 1)                        | (0, 1)                   (1,1)
 *                                |
 *                                |
 *                                |    <Baseline>
 * <Sad>                <Neutral> |    (0.45, 0.2)           <Pleased>
 * (-1, 0)                (0,0)   |                          (1, 0)
 * <-(-1)-------------------------+---------------------(+1)> *Valence*
 *                                |
 *                                |
 *                                |
 *                                |
 *                                |
 * <Frustrated>                   |  <Insecure>              <Determined>
 * (-1, -1)                       |  (0, -1)                 (1,-1)
 * ```
 *
 * @namespace jibo.emotion
 */
export {
    api,
    appraisal,
    common,
    emotion,
    emotionSystem,
    expression,
    sensing
};
