import {Sensor} from './Sensor';
import {EmotionSystem} from "../../EmotionSystem";
import {IdentityEvents} from "../../common/Types";

export {};

/**
 * @internal
 */
type IDEventHandler = () => void;

/**
 * @internal
 */
export class IdentitySensor extends Sensor<any> {

    static SENSOR_NAME = 'IdentitySensor';
    private presenceStartedHandler:IDEventHandler;
    private visibleFaceStartedHandler:IDEventHandler;
    private idAcquiredHandler:IDEventHandler;

    constructor(parent: EmotionSystem) {
        super(IdentitySensor.SENSOR_NAME, true, parent);
    }

    init() {
        super.init();
        this.presenceStartedHandler = () => {
            this.supplyData(IdentityEvents.PRESENCE_STARTED);
        };
        this.visibleFaceStartedHandler = () => {
            this.supplyData(IdentityEvents.VISIBLE_FACE_STARTED);
        };
        this.idAcquiredHandler = () => {
            this.supplyData(IdentityEvents.ID_ACQUIRED);
        };

        // when people come around him, he's excited
        this.parent.jibo.lps.identity.events.presenceStarted.on(this.presenceStartedHandler);
        this.parent.jibo.lps.identity.events.visibleFaceStarted.on(this.visibleFaceStartedHandler);
        // when he recognizes someone, he's confident
        this.parent.jibo.lps.identity.events.idAcquired.on(this.idAcquiredHandler);
    }

    /**
     * Deallocate and clean up any resources that were created.
     */
    dispose() {
        super.dispose();
        this.parent.jibo.lps.identity.events.presenceStarted.removeListener(this.presenceStartedHandler);
        this.parent.jibo.lps.identity.events.visibleFaceStarted.removeListener(this.visibleFaceStartedHandler);
        this.parent.jibo.lps.identity.events.idAcquired.removeListener(this.idAcquiredHandler);
    }

}
