import {Sensor} from './Sensor';
import {EmotionSystem} from "../../EmotionSystem";
// Only importing type definition
import JiboImport = require('../../../../jibo');

export {};

function isSuccessResult(result: JiboImport.jetstream.types.TurnResult): result is JiboImport.jetstream.types.SuccessTurnResult {
    return result.hasOwnProperty('result');
}

/**
 * @internal
 */
export class ASRInputSensor extends Sensor<string> {

    static SENSOR_NAME: string = 'ASRInputSensor';
    private onCloudReceived: (cloud:JiboImport.jetstream.types.TurnResult) => void;

    constructor(parent: EmotionSystem) {
        super(ASRInputSensor.SENSOR_NAME, true, parent);
    }

    init() {
        super.init();
        // attach our onCloudReceived callback to the GL's cloudReceived Event
        this.onCloudReceived = ((cloud) => {
            if (cloud.status === this.parent.jibo.jetstream.types.TurnResultType.SUCCEEDED && isSuccessResult(cloud)) {
                this.supplyData(cloud.result.asr.text);
            }
        });
        this.parent.jibo.jetstream.events.globalTurnResult.on(this.onCloudReceived);
        this.parent.jibo.jetstream.events.localTurnResult.on(this.onCloudReceived);
    }

    /**
     * Clean up any resources we left around
     */
    dispose() {
        super.dispose();
        // remove our onCloudReceived callback from the GL's cloudReceived Event
        this.parent.jibo.jetstream.events.globalTurnResult.off(this.onCloudReceived);
        this.parent.jibo.jetstream.events.localTurnResult.off(this.onCloudReceived);
    }
}
